using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestHelper
    {
        public static SchoolContext CreateContext(string dbName = null)
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName ?? Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }

        public static SchoolContext CreateSeededContext(string dbName = null)
        {
            var name = dbName ?? Guid.NewGuid().ToString();
            var context = CreateContext(name);
            SeedDatabase(context);
            return context;
        }

        public static void SeedDatabase(SchoolContext context)
        {
            // Departments
            var dept1 = new Department
            {
                Name = "Engineering",
                Budget = 350000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            var dept2 = new Department
            {
                Name = "Mathematics",
                Budget = 100000,
                StartDate = DateTime.Parse("2007-09-01")
            };
            context.Departments.AddRange(dept1, dept2);
            context.SaveChanges();

            // Instructors
            var instructor1 = new Instructor
            {
                FirstMidName = "Kim",
                LastName = "Abercrombie",
                HireDate = DateTime.Parse("1995-03-11"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Thompson 304" }
            };
            var instructor2 = new Instructor
            {
                FirstMidName = "Fadi",
                LastName = "Fakhouri",
                HireDate = DateTime.Parse("2002-07-06"),
                CourseAssignments = new List<CourseAssignment>(),
                OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
            };
            context.Instructors.AddRange(instructor1, instructor2);
            context.SaveChanges();

            // Link departments to administrators
            dept1.InstructorID = instructor1.ID;
            dept2.InstructorID = instructor2.ID;
            context.SaveChanges();

            // Courses
            var course1 = new Course
            {
                CourseID = 1050,
                Title = "Chemistry",
                Credits = 3,
                DepartmentID = dept1.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            var course2 = new Course
            {
                CourseID = 1045,
                Title = "Calculus",
                Credits = 4,
                DepartmentID = dept2.DepartmentID,
                Enrollments = new List<Enrollment>(),
                CourseAssignments = new List<CourseAssignment>()
            };
            context.Courses.AddRange(course1, course2);
            context.SaveChanges();

            // Course assignments
            var ca1 = new CourseAssignment { InstructorID = instructor1.ID, CourseID = course1.CourseID };
            var ca2 = new CourseAssignment { InstructorID = instructor2.ID, CourseID = course2.CourseID };
            context.CourseAssignments.AddRange(ca1, ca2);
            context.SaveChanges();

            // Students
            var student1 = new Student
            {
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.Parse("2010-09-01"),
                Enrollments = new List<Enrollment>()
            };
            var student2 = new Student
            {
                FirstMidName = "Meredith",
                LastName = "Alonso",
                EnrollmentDate = DateTime.Parse("2012-09-01"),
                Enrollments = new List<Enrollment>()
            };
            var student3 = new Student
            {
                FirstMidName = "Arturo",
                LastName = "Anand",
                EnrollmentDate = DateTime.Parse("2013-09-01"),
                Enrollments = new List<Enrollment>()
            };
            context.Students.AddRange(student1, student2, student3);
            context.SaveChanges();

            // Enrollments
            var enrollment1 = new Enrollment
            {
                StudentID = student1.ID,
                CourseID = course1.CourseID,
                Grade = Grade.A
            };
            var enrollment2 = new Enrollment
            {
                StudentID = student2.ID,
                CourseID = course2.CourseID,
                Grade = Grade.B
            };
            context.Enrollments.AddRange(enrollment1, enrollment2);
            context.SaveChanges();
        }

        /// <summary>
        /// Drains the static NotificationService queue to ensure test isolation.
        /// </summary>
        public static void DrainNotificationQueue()
        {
            using var service = new NotificationService();
            while (service.ReceiveNotification() != null) { }
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        [DataRow(10, 3, 4, DisplayName = "10 items, page size 3 = 4 pages")]
        [DataRow(9, 3, 3, DisplayName = "9 items, page size 3 = 3 pages")]
        [DataRow(0, 3, 0, DisplayName = "0 items, page size 3 = 0 pages")]
        [DataRow(1, 3, 1, DisplayName = "1 item, page size 3 = 1 page")]
        [DataRow(6, 3, 2, DisplayName = "6 items, page size 3 = 2 pages")]
        [DataRow(7, 3, 3, DisplayName = "7 items, page size 3 = 3 pages")]
        public void Constructor_CalculatesTotalPages(int count, int pageSize, int expectedPages)
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedPages, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            // Arrange
            var items = new List<string> { "alpha", "beta", "gamma" };

            // Act
            var list = new PaginatedList<string>(items, 3, 1, 3);

            // Assert
            Assert.AreEqual(3, list.Count);
            Assert.AreEqual("alpha", list[0]);
            Assert.AreEqual("beta", list[1]);
            Assert.AreEqual("gamma", list[2]);
        }

        [TestMethod]
        public void HasPreviousPage_FirstPage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_SecondPage_ReturnsTrue()
        {
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasNextPage_LastPage_ReturnsFalse()
        {
            // 10 items, page size 5 = 2 pages. Page 2 is last.
            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_NotLastPage_ReturnsTrue()
        {
            // 10 items, page size 5 = 2 pages. Page 1 is not last.
            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void Create_ReturnsCorrectPageItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act - get page 2 with page size 5
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(7, result[1]);
            Assert.AreEqual(10, result[4]);
        }

        [TestMethod]
        public void Create_SetsCorrectTotalPages()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_SetsCorrectPageIndex()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);
            Assert.AreEqual(3, result.PageIndex);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
        }

        [TestMethod]
        public void Create_FirstPage_HasNoPreviewPageButHasNextPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsTrue(result.HasNextPage);
        }

        [TestMethod]
        public void Create_LastPage_HasPreviousPageButNoNextPage()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();
            var result = PaginatedList<int>.Create(source, 4, 5);

            Assert.IsTrue(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // 13 items, page size 5 → page 3 should have 3 items
            var source = Enumerable.Range(1, 13).AsQueryable();
            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.AreEqual(3, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(13, result[2]);
        }

        [TestMethod]
        public void Create_SingleItem_SinglePage()
        {
            var source = new[] { 42 }.AsQueryable();
            var result = PaginatedList<int>.Create(source, 1, 10);

            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(42, result[0]);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }
    }
}

