using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void Setup()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from static queue to ensure isolation
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            // Drain again to clean up after test
            while (_service.ReceiveNotification() != null) { }
            _service?.Dispose();
        }

        [TestMethod]
        public void SendNotification_EnqueuesNotification_CanBeReceived()
        {
            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE, "TestUser");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("TestUser", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithDisplayName_IncludesNameInMessage()
        {
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.CREATE, "Admin");
            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Course 'Chemistry' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "101", EntityOperation.CREATE, "Admin");
            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual("New Course (ID: 101) has been created", notification.Message);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Student 'John' has been created")]
        [DataRow(EntityOperation.UPDATE, "Student 'John' has been updated")]
        [DataRow(EntityOperation.DELETE, "Student 'John' has been deleted")]
        public void SendNotification_OperationTypes_GenerateCorrectMessage(EntityOperation op, string expectedMessage)
        {
            _service.SendNotification("Student", "1", "John", op, "Admin");
            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_ReturnsInFifoOrder()
        {
            // Arrange
            _service.SendNotification("First", "1", EntityOperation.CREATE);
            _service.SendNotification("Second", "2", EntityOperation.UPDATE);

            // Act
            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("First", first.EntityType);
            Assert.AreEqual("Second", second.EntityType);
        }

        [TestMethod]
        public void ReceiveNotification_RemovesFromQueue()
        {
            _service.SendNotification("Test", "1", EntityOperation.CREATE);

            // First receive should return the notification
            var first = _service.ReceiveNotification();
            Assert.IsNotNull(first);

            // Second receive should return null (queue empty)
            var second = _service.ReceiveNotification();
            Assert.IsNull(second);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Test", "1", EntityOperation.CREATE, null);
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_SetsCreatedAtToCurrentTime()
        {
            var before = System.DateTime.Now.AddSeconds(-1);
            _service.SendNotification("Test", "1", EntityOperation.CREATE);
            var after = System.DateTime.Now.AddSeconds(1);

            var notification = _service.ReceiveNotification();

            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before, "CreatedAt should be >= test start");
            Assert.IsTrue(notification.CreatedAt <= after, "CreatedAt should be <= test end");
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Test", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op in the in-memory implementation
            _service.MarkAsRead(1);
            _service.MarkAsRead(999);
            _service.MarkAsRead(-1);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            _service.Dispose();
            _service.Dispose(); // Should not throw
        }

        [TestMethod]
        public void SendNotification_MultipleNotifications_AllReceivable()
        {
            // Arrange
            for (int i = 0; i < 5; i++)
            {
                _service.SendNotification("Type" + i, i.ToString(), EntityOperation.CREATE);
            }

            // Act & Assert
            for (int i = 0; i < 5; i++)
            {
                var notification = _service.ReceiveNotification();
                Assert.IsNotNull(notification, $"Notification {i} should not be null");
                Assert.AreEqual("Type" + i, notification.EntityType);
                Assert.AreEqual(i.ToString(), notification.EntityId);
            }

            // Queue should be empty now
            Assert.IsNull(_service.ReceiveNotification());
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "101", "", EntityOperation.UPDATE, "Admin");
            var notification = _service.ReceiveNotification();

            // Empty display name should fall through to the ID-based message
            Assert.AreEqual("Course (ID: 101) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Course", "101", "   ", EntityOperation.DELETE, "Admin");
            var notification = _service.ReceiveNotification();

            Assert.AreEqual("Course (ID: 101) has been deleted", notification.Message);
        }
    }
}

