+        [DataRow(1, 3, 1, DisplayName = "1 item, page size 3 = 1 page")]
+        [DataRow(6, 3, 2, DisplayName = "6 items, page size 3 = 2 pages")]
+        [DataRow(7, 3, 3, DisplayName = "7 items, page size 3 = 3 pages")]
+        public void Constructor_CalculatesTotalPages(int count, int pageSize, int expectedPages)
+        {
+            // Arrange & Act
+            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);
+
+            // Assert
+            Assert.AreEqual(expectedPages, list.TotalPages);
+        }
+
+        [TestMethod]
+        public void Constructor_AddsItemsToList()
+        {
+            // Arrange
+            var items = new List<string> { "alpha", "beta", "gamma" };
+
+            // Act
+            var list = new PaginatedList<string>(items, 3, 1, 3);
+
+            // Assert
+            Assert.AreEqual(3, list.Count);
+            Assert.AreEqual("alpha", list[0]);
+            Assert.AreEqual("beta", list[1]);
+            Assert.AreEqual("gamma", list[2]);
+        }
+
+        [TestMethod]
+        public void HasPreviousPage_FirstPage_ReturnsFalse()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+            Assert.IsFalse(list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasPreviousPage_SecondPage_ReturnsTrue()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+            Assert.IsTrue(list.HasPreviousPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_LastPage_ReturnsFalse()
+        {
+            // 10 items, page size 5 = 2 pages. Page 2 is last.
+            var list = new PaginatedList<int>(new List<int>(), 10, 2, 5);
+            Assert.IsFalse(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_NotLastPage_ReturnsTrue()
+        {
+            // 10 items, page size 5 = 2 pages. Page 1 is not last.
+            var list = new PaginatedList<int>(new List<int>(), 10, 1, 5);
+            Assert.IsTrue(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void HasNextPage_SinglePage_ReturnsFalse()
+        {
+            var list = new PaginatedList<int>(new List<int>(), 3, 1, 5);
+            Assert.IsFalse(list.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_ReturnsCorrectPageItems()
+        {
+            // Arrange
+            var source = Enumerable.Range(1, 20).AsQueryable();
+
+            // Act - get page 2 with page size 5
+            var result = PaginatedList<int>.Create(source, 2, 5);
+
+            // Assert
+            Assert.AreEqual(5, result.Count);
+            Assert.AreEqual(6, result[0]);
+            Assert.AreEqual(7, result[1]);
+            Assert.AreEqual(10, result[4]);
+        }
+
+        [TestMethod]
+        public void Create_SetsCorrectTotalPages()
+        {
+            var source = Enumerable.Range(1, 20).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 5);
+            Assert.AreEqual(4, result.TotalPages);
+        }
+
+        [TestMethod]
+        public void Create_SetsCorrectPageIndex()
+        {
+            var source = Enumerable.Range(1, 20).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 3, 5);
+            Assert.AreEqual(3, result.PageIndex);
+        }
+
+        [TestMethod]
+        public void Create_EmptySource_ReturnsEmptyList()
+        {
+            var source = Enumerable.Empty<int>().AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 5);
+
+            Assert.AreEqual(0, result.Count);
+            Assert.AreEqual(0, result.TotalPages);
+        }
+
+        [TestMethod]
+        public void Create_FirstPage_HasNoPreviewPageButHasNextPage()
+        {
+            var source = Enumerable.Range(1, 20).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 5);
+
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsTrue(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_LastPage_HasPreviousPageButNoNextPage()
+        {
+            var source = Enumerable.Range(1, 20).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 4, 5);
+
+            Assert.IsTrue(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+
+        [TestMethod]
+        public void Create_LastPage_ReturnsRemainingItems()
+        {
+            // 13 items, page size 5 → page 3 should have 3 items
+            var source = Enumerable.Range(1, 13).AsQueryable();
+            var result = PaginatedList<int>.Create(source, 3, 5);
+
+            Assert.AreEqual(3, result.Count);
+            Assert.AreEqual(11, result[0]);
+            Assert.AreEqual(13, result[2]);
+        }
+
+        [TestMethod]
+        public void Create_SingleItem_SinglePage()
+        {
+            var source = new[] { 42 }.AsQueryable();
+            var result = PaginatedList<int>.Create(source, 1, 10);
+
+            Assert.AreEqual(1, result.Count);
+            Assert.AreEqual(42, result[0]);
+            Assert.AreEqual(1, result.TotalPages);
+            Assert.IsFalse(result.HasPreviousPage);
+            Assert.IsFalse(result.HasNextPage);
+        }
+    }
+}
