using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class HomeControllerTests
    {
        private SchoolContext _context;
        private HomeController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateContext();
            _controller = new HomeController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void About_WithNoStudents_ReturnsEmptyList()
        {
            var result = _controller.About() as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(0, model.Count);
        }

        [TestMethod]
        public void About_WithStudents_ReturnsGroupedEnrollmentData()
        {
            // Arrange - add students with different enrollment dates
            _context.Students.Add(new Student
            {
                FirstMidName = "A", LastName = "One",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            });
            _context.Students.Add(new Student
            {
                FirstMidName = "B", LastName = "Two",
                EnrollmentDate = DateTime.Parse("2020-09-01")
            });
            _context.Students.Add(new Student
            {
                FirstMidName = "C", LastName = "Three",
                EnrollmentDate = DateTime.Parse("2021-09-01")
            });
            _context.SaveChanges();

            // Act
            var result = _controller.About() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<EnrollmentDateGroup>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);

            var group2020 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2020-09-01"));
            Assert.AreEqual(2, group2020.StudentCount);

            var group2021 = model.Single(g => g.EnrollmentDate == DateTime.Parse("2021-09-01"));
            Assert.AreEqual(1, group2021.StudentCount);
        }

        [TestMethod]
        public void Contact_ReturnsViewResult()
        {
            var result = _controller.Contact();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Contact_SetsViewBagMessage()
        {
            var result = _controller.Contact() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("Your contact page.", result.ViewData["Message"]);
        }

        [TestMethod]
        public void Error_ReturnsViewResult()
        {
            var result = _controller.Error();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Unauthorized_ReturnsViewResult()
        {
            var result = _controller.Unauthorized();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }

        [TestMethod]
        public void Unauthorized_SetsViewBagMessage()
        {
            var result = _controller.Unauthorized() as ViewResult;

            Assert.IsNotNull(result);
            Assert.AreEqual("You don't have permission to access this resource.", result.ViewData["Message"]);
        }
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Controllers;
