namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateSeededContext();
            _controller = new StudentsController(_context);

            // Set up TempData for controller (needed for DeleteConfirmed error path)
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                Mock.Of<ITempDataProvider>());
        }

        [TestCleanup]
        public void Cleanup()
        {
            _controller?.Dispose();
            _context?.Dispose();
        }

        // ========== Index Tests ==========

        [TestMethod]
        public void Index_DefaultSort_ReturnsViewWithStudentsOrderedByLastName()
        {
            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.IsTrue(model.Count > 0);
            // Should be ordered by LastName ascending: Alexander, Alonso, Anand
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_ReturnsStudentsOrderedByLastNameDescending()
        {
            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // Should be ordered by LastName descending: Anand, Alonso, Alexander
            Assert.AreEqual("Anand", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Alexander", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_ReturnsStudentsOrderedByEnrollmentDate()
        {
            var result = _controller.Index("Date", null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // Should be ordered by EnrollmentDate ascending
            Assert.IsTrue(model[0].EnrollmentDate <= model[1].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDescSort_ReturnsStudentsOrderedByEnrollmentDateDescending()
        {
            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // Should be ordered by EnrollmentDate descending
            Assert.IsTrue(model[0].EnrollmentDate >= model[1].EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchFilter_ReturnsMatchingStudents()
        {
            var result = _controller.Index(null, null, "Alexander", null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_ReturnsMatchingStudents()
        {
            var result = _controller.Index(null, null, "Carson", null) as ViewResult;

            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Carson", model[0].FirstMidName);
