            Assert.IsTrue(departmentNames.Contains("English"));
            Assert.IsTrue(departmentNames.Contains("Mathematics"));
            Assert.IsTrue(departmentNames.Contains("Engineering"));
            Assert.IsTrue(departmentNames.Contains("Economics"));
        }

