        public void Initialize_EnrollmentsHaveValidGrades()
        {
            using var context = TestHelper.CreateContext();
            DbInitializer.Initialize(context);

            var enrollmentsWithGrades = context.Enrollments.Where(e => e.Grade != null).ToList();
            Assert.IsTrue(enrollmentsWithGrades.Count > 0);

            // Verify grades are valid enum values
            foreach (var enrollment in enrollmentsWithGrades)
            {
                Assert.IsTrue(Enum.IsDefined(typeof(Grade), enrollment.Grade.Value));
            }
        }

        [TestMethod]
        public void Initialize_SomeEnrollmentsHaveNoGrade()
        {
            using var context = TestHelper.CreateContext();
            DbInitializer.Initialize(context);

            var enrollmentsWithoutGrades = context.Enrollments.Where(e => e.Grade == null).ToList();
            Assert.IsTrue(enrollmentsWithoutGrades.Count > 0);
        }
    }
