    {
        private SchoolContext _context;
        private NotificationsController _controller;

        [TestInitialize]
        public void Setup()
        {
            TestHelper.DrainNotificationQueue();
            _context = TestHelper.CreateContext();
            _controller = new NotificationsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            TestHelper.DrainNotificationQueue();
            _controller?.Dispose();
            _context?.Dispose();
        }

        // ========== GetNotifications Tests ==========

        [TestMethod]
        public void GetNotifications_EmptyQueue_ReturnsSuccess()
        {
            var result = _controller.GetNotifications();

            Assert.IsNotNull(result);
            Assert.IsNotNull(result.Value);

            var json = JsonSerializer.Serialize(result.Value);
            Assert.IsTrue(json.Contains("\"success\":true"));
            Assert.IsTrue(json.Contains("\"count\":0"));
        }

        [TestMethod]
        public void GetNotifications_WithNotifications_ReturnsNotifications()
        {
            // Arrange - enqueue notifications via the static queue
            using var service = new NotificationService();
            service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "Admin");
            service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE, "Admin");

            // Act
            var result = _controller.GetNotifications();

            // Assert
            Assert.IsNotNull(result);
            var json = JsonSerializer.Serialize(result.Value);
            Assert.IsTrue(json.Contains("\"success\":true"));
            Assert.IsTrue(json.Contains("\"count\":2"));
        }

        [TestMethod]
        public void GetNotifications_ReturnsJsonResult()
        {
            var result = _controller.GetNotifications();

            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        [TestMethod]
        public void GetNotifications_LimitsTo10Notifications()
        {
            // Arrange - enqueue 15 notifications
            using var service = new NotificationService();
            for (int i = 0; i < 15; i++)
            {
                service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            // Act
            var result = _controller.GetNotifications();

            // Assert
            var json = JsonSerializer.Serialize(result.Value);
            Assert.IsTrue(json.Contains("\"count\":10"));
        }

        // ========== MarkAsRead Tests ==========

        [TestMethod]
        public void MarkAsRead_ReturnsSuccess()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsNotNull(result);
            var json = JsonSerializer.Serialize(result.Value);
            Assert.IsTrue(json.Contains("\"success\":true"));
        }

        [TestMethod]
        public void MarkAsRead_ReturnsJsonResult()
        {
            var result = _controller.MarkAsRead(1);

            Assert.IsInstanceOfType(result, typeof(JsonResult));
        }

        // ========== Index Tests ==========

        [TestMethod]
        public void Index_ReturnsViewResult()
        {
            var result = _controller.Index();

            Assert.IsInstanceOfType(result, typeof(ViewResult));
        }
    }
