        public void SchoolContext_CanAddAndRetrieveCourse()
        {
            using var context = TestHelper.CreateContext();
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Now };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 5001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
