        [TestMethod]
        public void SchoolContext_CourseAssignment_HasCompositeKey()
        {
            using var context = TestHelper.CreateContext();

            // Add prerequisites
            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01")
            };
            context.Instructors.Add(instructor);
            var dept = new Department { Name = "Test", Budget = 1000, StartDate = DateTime.Now };
            context.Departments.Add(dept);
            context.SaveChanges();

            var course = new Course
            {
                CourseID = 6001,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            context.Courses.Add(course);
            context.SaveChanges();

            // Add course assignment with composite key
            var ca = new CourseAssignment
            {
                InstructorID = instructor.ID,
                CourseID = course.CourseID
            };
            context.CourseAssignments.Add(ca);
            context.SaveChanges();

            // Retrieve by composite key
            var retrieved = context.CourseAssignments.Find(course.CourseID, instructor.ID);
            Assert.IsNotNull(retrieved);
        }

        [TestMethod]
        public void SchoolContext_InstructorOfficeAssignment_OneToOne()
        {
            using var context = TestHelper.CreateContext();

            var instructor = new Instructor
            {
                FirstMidName = "Test",
                LastName = "Instructor",
                HireDate = DateTime.Parse("2020-01-01"),
                OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
            };
            context.Instructors.Add(instructor);
            context.SaveChanges();

            var retrieved = context.Instructors
                .Include(i => i.OfficeAssignment)
                .Single(i => i.ID == instructor.ID);

            Assert.IsNotNull(retrieved.OfficeAssignment);
            Assert.AreEqual("Room 101", retrieved.OfficeAssignment.Location);
            Assert.AreEqual(instructor.ID, retrieved.OfficeAssignment.InstructorID);
        }

        [TestMethod]
        public void SchoolContext_CanStoreAndRetrieveNotification()
        {
            using var context = TestHelper.CreateContext();
            var notification = new Notification
            {
                EntityType = "Student",
                EntityId = "1",
                Operation = "CREATE",
                Message = "Test notification",
                CreatedAt = DateTime.Now,
                CreatedBy = "TestUser",
                IsRead = false
            };

            context.Notifications.Add(notification);
            context.SaveChanges();

            var retrieved = context.Notifications.First();
            Assert.AreEqual("Student", retrieved.EntityType);
            Assert.AreEqual("CREATE", retrieved.Operation);
            Assert.AreEqual("Test notification", retrieved.Message);
        }

        [TestMethod]
        public void SchoolContext_TPH_StudentAndInstructorInPeopleTable()
        {
            using var context = TestHelper.CreateContext();

            context.Students.Add(new Student
            {
                FirstMidName = "StudentFirst",
                LastName = "StudentLast",
                EnrollmentDate = DateTime.Now
            });
            context.Instructors.Add(new Instructor
            {
                FirstMidName = "InstructorFirst",
                LastName = "InstructorLast",
                HireDate = DateTime.Now
            });
            context.SaveChanges();

            // Both should be in People table via TPH
            Assert.AreEqual(2, context.People.Count());
            Assert.AreEqual(1, context.Students.Count());
            Assert.AreEqual(1, context.Instructors.Count());
        }
    }
}

