+    {
+        [TestMethod]
+        public void Initialize_EmptyDatabase_SeedsStudents()
+        {
+            // Arrange
+            using var context = TestHelper.CreateContext();
+
+            // Act
+            DbInitializer.Initialize(context);
+
+            // Assert
+            Assert.AreEqual(8, context.Students.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_EmptyDatabase_SeedsInstructors()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            Assert.AreEqual(5, context.Instructors.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_EmptyDatabase_SeedsDepartments()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            Assert.AreEqual(4, context.Departments.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_EmptyDatabase_SeedsCourses()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            Assert.AreEqual(7, context.Courses.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_EmptyDatabase_SeedsEnrollments()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            Assert.IsTrue(context.Enrollments.Count() > 0);
+            Assert.AreEqual(11, context.Enrollments.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            Assert.AreEqual(3, context.OfficeAssignments.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_EmptyDatabase_SeedsCourseAssignments()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            Assert.AreEqual(8, context.CourseAssignments.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_WithExistingStudents_DoesNotReseed()
+        {
+            // Arrange - add a student first
+            using var context = TestHelper.CreateContext();
+            context.Students.Add(new Student
+            {
+                FirstMidName = "Existing",
+                LastName = "Student",
+                EnrollmentDate = DateTime.Parse("2020-01-01")
+            });
+            context.SaveChanges();
+
+            // Act
+            DbInitializer.Initialize(context);
+
+            // Assert - should still have just the one student
+            Assert.AreEqual(1, context.Students.Count());
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsCorrectStudentNames()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            var studentNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
+            Assert.IsTrue(studentNames.Contains("Alexander"));
+            Assert.IsTrue(studentNames.Contains("Alonso"));
+            Assert.IsTrue(studentNames.Contains("Anand"));
+            Assert.IsTrue(studentNames.Contains("Barzdukas"));
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsCorrectDepartmentNames()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            var departmentNames = context.Departments.Select(d => d.Name).OrderBy(n => n).ToList();
+            Assert.AreEqual(4, departmentNames.Count);
+            Assert.IsTrue(departmentNames.Contains("English"));
+            Assert.IsTrue(departmentNames.Contains("Mathematics"));
+            Assert.IsTrue(departmentNames.Contains("Engineering"));
+            Assert.IsTrue(departmentNames.Contains("Economics"));
+        }
+
+        [TestMethod]
+        public void Initialize_SeedsCorrectCourseIds()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            var courseIds = context.Courses.Select(c => c.CourseID).OrderBy(id => id).ToList();
+            CollectionAssert.Contains(courseIds, 1050); // Chemistry
+            CollectionAssert.Contains(courseIds, 1045); // Calculus
+            CollectionAssert.Contains(courseIds, 2021); // Composition
+            CollectionAssert.Contains(courseIds, 4022); // Microeconomics
+        }
+
+        [TestMethod]
+        public void Initialize_EnrollmentsHaveValidGrades()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            var enrollmentsWithGrades = context.Enrollments.Where(e => e.Grade != null).ToList();
+            Assert.IsTrue(enrollmentsWithGrades.Count > 0);
+
+            // Verify grades are valid enum values
+            foreach (var enrollment in enrollmentsWithGrades)
+            {
+                Assert.IsTrue(Enum.IsDefined(typeof(Grade), enrollment.Grade.Value));
+            }
+        }
+
+        [TestMethod]
+        public void Initialize_SomeEnrollmentsHaveNoGrade()
+        {
+            using var context = TestHelper.CreateContext();
+            DbInitializer.Initialize(context);
+
+            var enrollmentsWithoutGrades = context.Enrollments.Where(e => e.Grade == null).ToList();
+            Assert.IsTrue(enrollmentsWithoutGrades.Count > 0);
+        }
+    }
+}
